--- 文件: D:\LLM\memory\agentmemory\src\state\reranker.ts (第 1 至 74 行，共 74 行) ---
   1 | import type { HybridSearchResult } from "../types.js";
   2 | 
   3 | let pipeline: any = null;
   4 | let pipelineLoading: Promise<any> | null = null;
   5 | let pipelineUnavailable = false;
   6 | 
   7 | async function loadPipeline(): Promise<any> {
   8 |   if (pipelineUnavailable) return null;
   9 |   if (pipeline) return pipeline;
  10 |   if (pipelineLoading) return pipelineLoading;
  11 | 
  12 |   pipelineLoading = (async () => {
  13 |     try {
  14 |       const { pipeline: createPipeline } = await import(
  15 |         "@xenova/transformers"
  16 |       );
  17 |       pipeline = await createPipeline(
  18 |         "text-classification",
  19 |         "Xenova/ms-marco-MiniLM-L-6-v2",
  20 |         { quantized: true },
  21 |       );
  22 |       return pipeline;
  23 |     } catch {
  24 |       pipeline = null;
  25 |       pipelineUnavailable = true;
  26 |       return null;
  27 |     } finally {
  28 |       pipelineLoading = null;
  29 |     }
  30 |   })();
  31 |   return pipelineLoading;
  32 | }
  33 | 
  34 | export async function rerank(
  35 |   query: string,
  36 |   results: HybridSearchResult[],
  37 |   topK = 20,
  38 | ): Promise<HybridSearchResult[]> {
  39 |   if (results.length <= 1) return results;
  40 | 
  41 |   const reranker = await loadPipeline();
  42 |   if (!reranker) return results;
  43 | 
  44 |   const candidates = results.slice(0, Math.min(results.length, topK));
  45 | 
  46 |   const pairs = candidates.map((r) => ({
  47 |     text: `${query} [SEP] ${r.observation.title || ""} ${r.observation.narrative || ""}`.slice(0, 512),
  48 |     result: r,
  49 |   }));
  50 | 
  51 |   const scores: Array<{ result: HybridSearchResult; rerankScore: number }> = [];
  52 | 
  53 |   for (const pair of pairs) {
  54 |     try {
  55 |       const output = await reranker(pair.text);
  56 |       const score = Array.isArray(output) ? output[0]?.score ?? 0 : 0;
  57 |       scores.push({ result: pair.result, rerankScore: score });
  58 |     } catch {
  59 |       scores.push({ result: pair.result, rerankScore: pair.result.combinedScore });
  60 |     }
  61 |   }
  62 | 
  63 |   scores.sort((a, b) => b.rerankScore - a.rerankScore);
  64 | 
  65 |   return scores.map((s, i) => ({
  66 |     ...s.result,
  67 |     combinedScore: s.rerankScore,
  68 |     rerankPosition: i + 1,
  69 |   }));
  70 | }
  71 | 
  72 | export function isRerankerAvailable(): boolean {
  73 |   return pipeline !== null;
  74 | }
--- 读取完毕 ---

